<?php
/**
 * Front-end include: Homepage Slider
 * Pulls active slides from cms_sliders (ordered by sort_order) and renders the Swiper carousel.
 * Images are stored under admin/uploads/sliders/ and served via ADMIN_UPLOAD_URL.
 * Falls back gracefully if no slides exist or DB is unavailable.
 */

$_slides = [];
try {
    $db = front_db();
    if ($db) {
        $_slides = $db->query(
            'SELECT title, subtitle, image, link_url, link_text
             FROM cms_sliders
             WHERE is_active = 1
             ORDER BY sort_order, id'
        )->fetchAll();
    }
} catch (Throwable $e) {
    // silently fall through
}

